const b = $input.first().json.body ?? $input.first().json;
const dataUrl = b.fotoFrenteBase64 ?? '';
const match = dataUrl.match(/^data:(image\/\w+);base64,(.+)$/);
if (!match) return [{ json: { erro: true } }];
const prompt = `Analise a pessoa na foto para criar um avatar cartoon. Responda APENAS com JSON válido, sem markdown:\n{\"skinTone\": \"um destes: #fbd7b5 #eab98c #c68863 #9c6644 #6f4a2f\", \"hair\": \"um destes: nenhum curto medio longo coque moicano cacheado\", \"hairColor\": \"um destes: #2f2a26 #5b4633 #8a6b47 #c98d3c #b45309 #94a3b8\", \"beard\": \"um destes: nenhuma bigode cavanhaque cheia\"}`;
return [{ json: { mediaType: match[1], data: match[2], prompt } }];

const texto = $input.first().json.content?.[0]?.text ?? '{}';
const limpo = texto.replace(/```json|```/g, '').trim();
let out = {};
try { out = JSON.parse(limpo); } catch (e) { out = {}; }
return [{ json: out }];
